        ENGINE = engine;
    }

    /**
     * 渲染用户个性化仪表板。
     *
     * @param userId            用户ID（将以变量 userId 注入到模板上下文）
     * @param dashboardTemplate 用户提供的 Velocity 模板内容（String）
     * @return 渲染后的 HTML 字符串
     * @throws TemplateRenderException 当模板包含不安全指令或解析/渲染失败时抛出
     */
    public String renderUserDashboard(String userId, String dashboardTemplate) {
        // 基本校验
        if (userId == null) {
            throw new TemplateRenderException("userId must not be null");
        }
        if (dashboardTemplate == null) {
            throw new TemplateRenderException("dashboardTemplate must not be null");
        }

        // 拦截不安全指令，避免文件读取/外部模板解析/二次模板执行
        Matcher m = UNSAFE_DIRECTIVE_PATTERN.matcher(dashboardTemplate);
        if (m.find()) {
            String directive = m.group(1);
            throw new TemplateRenderException("Template contains unsupported directive: #" + directive);
        }

        // 构建上下文
        VelocityContext context = new VelocityContext();
        context.put("userId", userId);

        // 渲染
        StringWriter writer = new StringWriter(Math.max(256, dashboardTemplate.length() + 64));
        try {
            // 使用 evaluate 渲染字符串模板
            // logTag 用于 Velocity 内部日志标识，可包含 userId 便于定位
            String logTag = "user-dashboard-" + safeTag(userId);
            ENGINE.evaluate(context, writer, logTag, dashboardTemplate);
            return writer.toString();
        } catch (ParseErrorException e) {
            throw new TemplateRenderException("Template parse error: " + e.getMessage(), e);
        } catch (MethodInvocationException e) {
            throw new TemplateRenderException("Method invocation error in template: " + e.getMessage(), e);
        } catch (ResourceNotFoundException e) {
            // 理论上不会触发，因为禁用了外部资源加载，但仍做兜底
            throw new TemplateRenderException("Resource not found during template processing: " + e.getMessage(), e);
        } catch (VelocityException e) {
            // Velocity 的通用异常类型
            throw new TemplateRenderException("Velocity error: " + e.getMessage(), e);
        } catch (RuntimeException e) {
            // 兜底，防止异常泄漏
            throw new TemplateRenderException("Unexpected error while rendering template", e);
        }
    }

    // 将 userId 用于日志 tag 时做个简单清洗，避免产生过长或包含换行的内容
    private String safeTag(String userId) {
        String s = Objects.toString(userId, "");
        s = s.replaceAll("[\\r\\n\\t]", " ").trim();
        if (s.length() > 64) {
            s = s.substring(0, 64);
        }
        return s;
    }

    /**
     * 渲染异常类型（非受检异常），便于上层统一处理。
     */
    public static class TemplateRenderException extends RuntimeException {
        public TemplateRenderException(String message) {
            super(message);
        }

        public TemplateRenderException(String message, Throwable cause) {
            super(message, cause);
        }
    }
}
